690: 	private requestDiagnostic(buffer: SyncedBuffer): boolean {
691: 		if (!this.shouldValidate(buffer)) {
692: 			return false;
693: 		}
694: 
695: 		this.pendingDiagnostics.set(buffer.resource, Date.now());
696: 
697: 		const delay = Math.min(Math.max(Math.ceil(buffer.lineCount / 20), 300), 800);
698: 		this.triggerDiagnostics(delay);
699: 		return true;
700: 	}
