27: export function activate(
28: 	context: vscode.ExtensionContext
29: ): Api {
30: 	const pluginManager = new PluginManager();
31: 	context.subscriptions.push(pluginManager);
32: 
33: 	const commandManager = new CommandManager();
34: 	context.subscriptions.push(commandManager);
35: 
36: 	const onCompletionAccepted = new vscode.EventEmitter<vscode.CompletionItem>();
37: 	context.subscriptions.push(onCompletionAccepted);
38: 
39: 	const logDirectoryProvider = new NodeLogDirectoryProvider(context);
40: 	const versionProvider = new DiskTypeScriptVersionProvider();
41: 
42: 	const activeJsTsEditorTracker = new ActiveJsTsEditorTracker();
43: 	context.subscriptions.push(activeJsTsEditorTracker);
44: 
45: 	let experimentTelemetryReporter: IExperimentationTelemetryReporter | undefined;
46: 	const packageInfo = getPackageInfo(context);
47: 	if (packageInfo) {
48: 		const { name: id, version, aiKey } = packageInfo;
49: 		const vscTelemetryReporter = new VsCodeTelemetryReporter(aiKey);
50: 		experimentTelemetryReporter = new ExperimentationTelemetryReporter(vscTelemetryReporter);
51: 		context.subscriptions.push(experimentTelemetryReporter);
52: 
53: 		// Currently we have no experiments, but creating the service adds the appropriate
54: 		// shared properties to the ExperimentationTelemetryReporter we just created.
55: 		new ExperimentationService(experimentTelemetryReporter, id, version, context.globalState);
56: 	}
57: 
58: 	const logger = new Logger();
59: 
60: 	const lazyClientHost = createLazyClientHost(context, onCaseInsensitiveFileSystem(), {
61: 		pluginManager,
62: 		commandManager,
63: 		logDirectoryProvider,
64: 		cancellerFactory: nodeRequestCancellerFactory,
65: 		versionProvider,
66: 		processFactory: new ElectronServiceProcessFactory(),
67: 		activeJsTsEditorTracker,
68: 		serviceConfigurationProvider: new ElectronServiceConfigurationProvider(),
69: 		experimentTelemetryReporter,
70: 		logger,
71: 	}, item => {
72: 		onCompletionAccepted.fire(item);
73: 	});
74: 
75: 	registerBaseCommands(commandManager, lazyClientHost, pluginManager, activeJsTsEditorTracker);
76: 
77: 	import('./task/taskProvider').then(module => {
78: 		context.subscriptions.push(module.register(lazyClientHost.map(x => x.serviceClient)));
79: 	});
80: 
81: 	import('./languageFeatures/tsconfig').then(module => {
82: 		context.subscriptions.push(module.register());
83: 	});
84: 
85: 	context.subscriptions.push(lazilyActivateClient(lazyClientHost, pluginManager, activeJsTsEditorTracker));
86: 
87: 	return getExtensionApi(onCompletionAccepted.event, pluginManager);
88: }
89: 
90: export function deactivate() {
91: 	fs.rmSync(temp.instanceTempDir.value, { recursive: true, force: true });
92: }
