import * as assert from 'assert';
import 'mocha';
import * as vscode from 'vscode';
import { createTestEditor, wait } from '../../test/testUtils';
import { disposeAll } from '../../utils/dispose';

suite.skip('TypeScript Diagnostics Refresh on File Change', () => {

	const _disposables: vscode.Disposable[] = [];

	setup(async () => {
		// the tests assume that typescript features are registered
		await vscode.extensions.getExtension('vscode.typescript-language-features')!.activate();
	});

	teardown(async () => {
		disposeAll(_disposables);

		await vscode.commands.executeCommand('workbench.action.closeAllEditors');
	});

	test('Diagnostics should refresh when file changes on disk', async () => {
		const testDocumentUri = vscode.Uri.parse('untitled:test.ts');

		const editor = await createTestEditor(testDocumentUri,
			`const foo: string = 123;`, // Type error: number is not assignable to string
		);

		// Wait for diagnostics to be collected
		await wait(500);

		// Get diagnostics for the file
		const diagnosticsAfterChange = vscode.languages.getDiagnostics(testDocumentUri);

		// Should have diagnostics for the type error
		assert.ok(diagnosticsAfterChange.length > 0, 'Expected diagnostics after file change');

		// Verify the diagnostic is a type error
		const typeDiagnostic = diagnosticsAfterChange.find(d =>
			d.message.includes('Type') || d.message.includes('not assignable')
		);
		assert.ok(typeDiagnostic, 'Expected type error diagnostic');
	});

	test('Stale diagnostics should be cleared when file content changes externally', async () => {
		const testDocumentUri = vscode.Uri.parse('untitled:test-stale.ts');

		const editor = await createTestEditor(testDocumentUri,
			`const x: number = 'hello';`, // Type error
		);

		// Wait for diagnostics to be collected
		await wait(500);

		const diagnosticsBeforeChange = vscode.languages.getDiagnostics(testDocumentUri);
		assert.ok(diagnosticsBeforeChange.length > 0, 'Expected initial diagnostics');

		// Simulate external file change by modifying the editor content to fix the error
		const edit = new vscode.WorkspaceEdit();
		edit.replace(testDocumentUri, new vscode.Range(0, 0, 0, 30), `const x: string = 'hello';`);
		await vscode.workspace.applyEdit(edit);

		// Wait for diagnostics to update
		await wait(500);

		const diagnosticsAfterChange = vscode.languages.getDiagnostics(testDocumentUri);
		// After fixing the error, there should be no type errors
		const typeErrors = diagnosticsAfterChange.filter(d =>
			d.message.includes('Type') || d.message.includes('not assignable')
		);
		assert.ok(typeErrors.length === 0, 'Expected type errors to be cleared after fixing the issue');
	});
});

