	test('Stale diagnostics should be cleared when file content changes externally', async () => {
		const testDocumentUri = vscode.Uri.parse('untitled:test-stale.ts');

		const editor = await createTestEditor(testDocumentUri,
			`const x: number = 'hello';`, // Type error
		);

		// Wait for diagnostics to be collected
		await wait(500);

		const diagnosticsBeforeChange = vscode.languages.getDiagnostics(testDocumentUri);
		assert.ok(diagnosticsBeforeChange.length > 0, 'Expected initial diagnostics');

		// Simulate external file change by modifying the editor content to fix the error
		const edit = new vscode.WorkspaceEdit();
		edit.replace(testDocumentUri, new vscode.Range(0, 0, 0, 30), `const x: string = 'hello';`);
		await vscode.workspace.applyEdit(edit);

		// Wait for diagnostics to update
		await wait(500);

		const diagnosticsAfterChange = vscode.languages.getDiagnostics(testDocumentUri);
		// After fixing the error, there should be no type errors
		const typeErrors = diagnosticsAfterChange.filter(d =>
			d.message.includes('Type') || d.message.includes('not assignable')
		);
		assert.ok(typeErrors.length === 0, 'Expected type errors to be cleared after fixing the issue');
	});
});

